'use client';

import { AdminNav } from '@/components/AdminNav';
import { RequireAuth } from '@/components/RequireAuth';
import { adminApi } from '@/lib/api';
import { useState } from 'react';

export default function ReportsPage() {
  const [summary, setSummary] = useState<any>(null);
  const [shift, setShift] = useState<any>(null);

  return (
    <RequireAuth>
      <main>
        <AdminNav />
        <div className="card">
          <h1>Reports</h1>
          <div className="grid2">
            <button onClick={async () => setSummary(await adminApi.reportSummary())}>Load Summary</button>
            <button onClick={async () => setShift(await adminApi.reportShift())}>Load Shift</button>
          </div>
        </div>
        {summary ? <div className="card"><pre>{JSON.stringify(summary, null, 2)}</pre></div> : null}
        {shift ? <div className="card"><pre>{JSON.stringify(shift, null, 2)}</pre></div> : null}
      </main>
    </RequireAuth>
  );
}
